def test_manager_unauthenticated_request_denied():
    payload = {
        "start_date": "2025-02-01",
        "end_date": "2025-02-05",
        "reason": "Personal leave",
        "employee_id": "EMP-001"
    }
    resp = requests.post(
        "http://localhost:8080/leave-requests",
        json=payload,
        headers={}
    )
    assert resp.status_code == 401

def test_non_manager_role_forbidden():
    auth_token = <login_employee_helper>
    payload = {
        "start_date": "2025-02-01",
        "end_date": "2025-02-05",
        "reason": "Personal leave",
        "employee_id": "EMP-001"
    }
    headers = {"Authorization": f"Bearer {auth_token}"}
    resp = requests.post(
        "http://localhost:8080/leave-requests",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 403

def test_leave_request_reason_exceeds_max_length():
    auth_token = <login_manager_helper>
    payload = {
        "start_date": "2025-02-01",
        "end_date": "2025-02-05",
        "reason": "x" * 2000,
        "employee_id": "EMP-001"
    }
    headers = {"Authorization": f"Bearer {auth_token}"}
    resp = requests.post(
        "http://localhost:8080/leave-requests",
        json=payload,
        headers=headers
    )
    assert resp.status_code == 400

def test_leave_request_empty_reason_field():
    auth_token = <login_manager_helper>
    payload = {
        "start_date": "2025-02-01",
        "end_date": "2025-02-05",
        "reason": "",
        "employee_id": "EMP-001"
    }
    headers = {"Authorization": f"Bearer {auth_token}"}
    resp = requests.post(
        "http://localhost:8080/leave-requests",
        json=payload,
        headers=headers
    )
    if <reason_is_mandatory>:
        assert resp.status_code == 400
    else:
        assert resp.status_code in [200, 201]
